   889→    fn add_move_error_details(&self, err: &mut Diag<'_>, binds_to: &[Local]) {
   890→        for (j, local) in binds_to.iter().enumerate() {
   891→            let bind_to = &self.body.local_decls[*local];
   892→            let binding_span = bind_to.source_info.span;
   893→
   894→            if j == 0 {
   895→                err.span_label(binding_span, "data moved here");
   896→            } else {
   897→                err.span_label(binding_span, "...and here");
   898→            }
   899→
   900→            if binds_to.len() == 1 {
   901→                let place_desc = self.local_name(*local).map(|sym| format!("`{sym}`"));
   902→
   903→                if let Some(expr) = self.find_expr(binding_span) {
   904→                    let local_place: PlaceRef<'tcx> = (*local).into();
   905→                    self.suggest_cloning(err, local_place, bind_to.ty, expr, None);
   906→                }
