   925→    /// Adds an explanatory note if the move error occurs in a derive macro
   926→    /// expansion of a packed struct.
   927→    /// Such errors happen because derive macro expansions shy away from taking
   928→    /// references to the struct's fields since doing so would be undefined behaviour
   929→    fn add_note_for_packed_struct_derive(&self, err: &mut Diag<'_>, local: Local) {
   930→        let local_place: PlaceRef<'tcx> = local.into();
   931→        let local_ty = local_place.ty(self.body.local_decls(), self.infcx.tcx).ty.peel_refs();
