   933→        if let Some(adt) = local_ty.ty_adt_def()
   934→            && adt.repr().packed()
   935→            && let ExpnKind::Macro(MacroKind::Derive, name) =
   936→                self.body.span.ctxt().outer_expn_data().kind
   937→        {
   938→            err.note(format!("`#[derive({name})]` triggers a move because taking references to the fields of a packed struct is undefined behaviour"));
   939→        }
   940→    }
