                        this.buffer_error(err);
                    }
                    ReadKind::Borrow(bk) => {
                        let err =
                            this.report_conflicting_borrow(location, place_span, bk, borrow);
                        this.buffer_error(err);
                    }
                }
                ControlFlow::Break(())
            }

