fn consume_operand(
    &mut self,
    location: Location,
    (operand, span): (&Operand<'tcx>, Span),
    state: &BorrowckDomain,
) {
    match *operand {
        Operand::Copy(place) => {
            // copy of place: check if this is "copy of frozen path"
            // (FIXME: see check_loans.rs)
            self.access_place(
                location,
                (place, span),
                (Deep, Read(ReadKind::Copy)),
                LocalMutationIsAllowed::No,
                state,
            );

            // Finally, check if path was already moved.
            self.check_if_path_or_subpath_is_moved(
                location,
                InitializationRequiringAction::Use,
                (place.as_ref(), span),
                state,
            );
        }
        Operand::Move(place) => {
            // Check if moving from this place makes sense.
            self.check_movable_place(location, place);

            // move of place: check if this is move of already borrowed path
            self.access_place(
                location,
                (place, span),
                (Deep, Write(WriteKind::Move)),
                LocalMutationIsAllowed::Yes,
                state,
            );

            // Finally, check if path was already moved.
            self.check_if_path_or_subpath_is_moved(
                location,
                InitializationRequiringAction::Use,
                (place.as_ref(), span),
                state,
            );
        }
        Operand::Constant(_) => {}
    }
}

/// Checks whether a borrow of this place is invalidated when the function
/// exits
#[instrument(level = "debug", skip(self))]
fn check_for_invalidation_at_exit(
    &mut self,
    location: Location,
    borrow: &BorrowData<'tcx>,
    span: Span,
) {
    let place = borrow.borrowed_place;
    let mut root_place = PlaceRef { local: place.local, projection: &[] };

    // FIXME(nll-rfc#40): do more precise destructor tracking here. For now
    // we just know that all locals are dropped at function exit (otherwise
    // we'll have a memory leak) and assume that all statics have a destructor.
    //
    // FIXME: allow thread-locals to borrow other thread locals?
    let might_be_alive = if self.body.local_decls[root_place.local].is_ref_to_thread_local() {
        // Thread-locals might be dropped after the function exits
        // We have to dereference the outer reference because
        // borrows don't conflict behind shared references.
        root_place.projection = TyCtxtConsts::DEREF_PROJECTION;
        true
    } else {
        false
    };

    let sd = if might_be_alive { Deep } else { Shallow(None) };

    if places_conflict::borrow_conflicts_with_place(
        self.infcx.tcx,
        self.body,
        place,
        borrow.kind,
        root_place,
        sd,
        places_conflict::PlaceConflictBias::Overlap,
    ) {
        debug!("check_for_invalidation_at_exit({:?}): INVALID", place);
        // FIXME: should be talking about the region lifetime instead
        // of just a span here.
        let span = self.infcx.tcx.sess.source_map().end_point(span);
        self.report_borrowed_value_does_not_live_long_enough(
            location,
            borrow,
            (place, span),
            None,
        )
    }
}

/// Reports an error if this is a borrow of local data.
/// This is called for all Yield expressions on movable coroutines
fn check_for_local_borrow(&mut self, borrow: &BorrowData<'tcx>, yield_span: Span) {
    debug!("check_for_local_borrow({:?})", borrow);

    if borrow_of_local_data(borrow.borrowed_place) {
        let err = self.cannot_borrow_across_coroutine_yield(
            self.retrieve_borrow_spans(borrow).var_or_use(),
            yield_span,
        );

        self.buffer_error(err);

